)
ON CONFLICT (program_type, phase_number) DO NOTHING;

-- =====================================================
-- 2. Структурированные критерии перехода shoulder_bankart
--    (JOIN на rehab_phases по program_type+phase_number → реальный phase_id)
--    Фаза 0 (prehab) — без structured-критериев. Фаза 6 (терминальная) — в источнике
--    transition_criteria ПУСТ → не включена. Включены фазы 1–5.
--    measurement = боль ВАШ (vas_score+pain) ТОЛЬКО; объём/градусы/сила/%/месяцы → instructor_check.
-- =====================================================
WITH criteria_data (
  phase_number, criterion_code, label, criterion_type,
  measurement_type, measurement_source,
  threshold_operator, threshold_value, threshold_value2,
  staleness_days, self_report_question, self_report_hint,
  position, is_required
) AS (VALUES
  -- Фаза 1 → Фаза 2 (иммобилизация и защита → защищённое восстановление движений)
  (1, 'passive_elevation_90_p1',  'Пассивный подъём руки не менее 90°',                                                        'instructor_check', NULL::varchar, NULL::varchar, NULL::varchar, NULL::numeric, NULL::numeric, 14::smallint, NULL::text, NULL::text, 10::smallint, TRUE),
  (1, 'passive_er_15_p1',         'Поворот руки наружу с локтем у тела не менее 15° (при некоторых вариантах операции допустимый порог ниже, ближе к 0–10°; решает куратор)', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 20::smallint, TRUE),
  (1, 'voluntary_contraction_p1', 'Мышцы вокруг лопатки и дельтовидная включаются произвольно, без болевого торможения (оценка куратора)', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 30::smallint, TRUE),
  (1, 'pain_no_infection_p1',     'Боль под контролем, нет признаков инфекции (температуры, обильного отделяемого из раны)',    'self_report',      NULL, NULL, NULL, NULL, NULL, 7::smallint, 'Боль под контролем и нет признаков инфекции — температуры, обильного отделяемого из раны?', 'Сравните с тем, как было в первые дни после операции', 40::smallint, TRUE),
  (1, 'no_complications_p1',      'Нет осложнений раннего этапа: рана, чувствительность и кровоснабжение кисти в норме (оценка куратора)', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 50::smallint, TRUE),

  -- Фаза 2 → Фаза 3 (защищённое восстановление движений → полный объём и ранняя сила)
  (2, 'passive_elevation_140_p2', 'Пассивный подъём руки не менее 140°',                                                       'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 10::smallint, TRUE),
  (2, 'passive_er_45_p2',         'Поворот руки наружу не менее 45°',                                                          'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 20::smallint, TRUE),
  (2, 'passive_ir_45_abd_p2',     'Поворот руки внутрь не менее 50°, полное пассивное отведение руки в сторону',                'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 30::smallint, TRUE),
  (2, 'sleep_no_sling_p2',        'Получается спать без слинга, не просыпаясь от боли',                                         'self_report',      NULL, NULL, NULL, NULL, NULL, 7::smallint, 'Можете спать без слинга, не просыпаясь от боли?', 'Оцените по нескольким последним ночам', 40::smallint, TRUE),
  (2, 'pain_le_2_p2',             'Боль при занятиях не более 2 из 10',                                                        'measurement',      'vas_score', 'pain', '<=', 2::numeric, NULL, 7::smallint, NULL, NULL, 50::smallint, TRUE),

  -- Фаза 3 → Фаза 4 (полный объём и ранняя сила → прогрессия силы)
  (3, 'elevation_160_p3',         'Подъём руки не менее 160°, полное отведение в сторону',                                      'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 10::smallint, TRUE),
  (3, 'er_at_abd_75_p3',          'Поворот руки наружу в положении «рука в сторону» не менее 75°',                              'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 20::smallint, TRUE),
  (3, 'negative_apprehension_p3', 'Нет тревоги и ощущения вывиха в провокационном положении (рука в сторону + поворот наружу) (оценка куратора)', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 30::smallint, TRUE),
  (3, 'scapular_mechanics_p3',    'Плечо и лопатка двигаются слаженно, минимум компенсаций (оценка куратора)',                  'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 40::smallint, FALSE),
  (3, 'pain_le_2_p3',             'Боль не более 2 из 10',                                                                     'measurement',      'vas_score', 'pain', '<=', 2::numeric, NULL, 7::smallint, NULL, NULL, 50::smallint, TRUE),

  -- Фаза 4 → Фаза 5 (прогрессия силы → возврат к функции и предспортивная подготовка)
  (4, 'full_painfree_rom_p4',     'Полный безболезненный объём движений (и активный, и пассивный)',                            'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 10::smallint, TRUE),
  (4, 'no_apprehension_p4',       'Нет тревоги и ощущения вывиха при нагрузке (оценка куратора)',                               'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 20::smallint, TRUE),
  (4, 'strength_5of5_p4',         'Сила плеча не менее 5 из 5 при осмотре или близка к симметрии со здоровой стороной',         'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 30::smallint, TRUE),
  (4, 'stable_in_adl_p4',         'Плечо ощущается стабильным при бытовой нагрузке',                                            'self_report',      NULL, NULL, NULL, NULL, NULL, 7::smallint, 'Чувствуете ли плечо стабильным при бытовой нагрузке?', 'Оцените по реальным повседневным делам', 40::smallint, TRUE),

  -- Фаза 5 → Фаза 6 (предспортивная подготовка → возврат к спорту и полной активности)
  (5, 'time_6mo_p5',              'Срок от операции не менее 6 месяцев для контактных видов (для неконтактных — ориентир 4–6 месяцев)', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 30::smallint, NULL, NULL, 10::smallint, TRUE),
  (5, 'rotators_90_pct_p5',       'Сила поворота руки наружу и внутрь не менее 90% от здоровой стороны',                        'instructor_check', NULL, NULL, NULL, NULL, NULL, 30::smallint, NULL, NULL, 20::smallint, TRUE),
  (5, 'functional_tests_85_p5',   'Функциональные тесты на руку не менее 85% от здоровой стороны',                              'instructor_check', NULL, NULL, NULL, NULL, NULL, 30::smallint, NULL, NULL, 30::smallint, TRUE),
  (5, 'no_instability_p5',        'Стойко нет тревоги и ощущения вывиха, нет признаков неустойчивости (оценка куратора)',       'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 40::smallint, TRUE),
  (5, 'psych_readiness_p5',       'Психологическая готовность вернуться к спорту (единого порога нет, оценивает куратор очно)', 'self_report',      NULL, NULL, NULL, NULL, NULL, 14::smallint, 'Чувствуете ли вы психологическую готовность и уверенность вернуться к спорту?', 'Оцените страх движения и доверие к плечу при спорт-нагрузке', 50::smallint, TRUE)
)
INSERT INTO phase_transition_criteria (
  phase_id, criterion_code, label, criterion_type,
  measurement_type, measurement_source,
  threshold_operator, threshold_value, threshold_value2, staleness_days,
  self_report_question, self_report_hint,
  position, is_required, is_active
)
SELECT
  p.id, cd.criterion_code, cd.label, cd.criterion_type,
  cd.measurement_type, cd.measurement_source,
  cd.threshold_operator, cd.threshold_value, cd.threshold_value2, cd.staleness_days,
  cd.self_report_question, cd.self_report_hint,
  cd.position, cd.is_required, TRUE
FROM criteria_data cd
JOIN rehab_phases p ON p.program_type = 'shoulder_bankart' AND p.phase_number = cd.phase_number
ON CONFLICT (phase_id, criterion_code) DO NOTHING;

COMMIT;
